const request = $input.first().json;
const rawHeaders = (request.headers && typeof request.headers === 'object' && !Array.isArray(request.headers)) ? request.headers : {};
const headers = Object.fromEntries(
  Object.entries(rawHeaders).map(([key, value]) => [String(key).toLowerCase(), value])
);
const sanitizedHeaders = Object.fromEntries(
  Object.entries(rawHeaders).filter(([key]) => {
    const normalizedKey = String(key).toLowerCase();
    return normalizedKey !== 'x-api-key' && normalizedKey !== 'authorization';
  })
);
const sanitizedRequest = {
  ...request,
  headers: sanitizedHeaders
};
const headerValue = (value) => Array.isArray(value) ? String(value[0] || '').trim() : String(value || '').trim();
const expectedApiKey = String($env.N8N_WEBHOOK_API_KEY || '').trim();
const xApiKey = headerValue(headers['x-api-key']);
const authorization = headerValue(headers.authorization);
const bearerMatch = authorization.match(/^Bearer\s+(.+)$/i);
const bearerToken = bearerMatch ? String(bearerMatch[1] || '').trim() : '';
const matchedXApiKey = Boolean(expectedApiKey) && xApiKey === expectedApiKey;
const matchedBearer = Boolean(expectedApiKey) && bearerToken === expectedApiKey;
const authenticated = matchedXApiKey || matchedBearer;

if (authenticated) {
  return [{
    json: {
      ...sanitizedRequest,
      webhook_auth: {
        authenticated: true,
        header: matchedXApiKey ? 'X-API-Key' : 'Authorization'
      }
    },
    pairedItem: {
      item: 0
    }
  }];
}

const message = 'Unauthorized: Invalid or missing API key';

return [{
  json: {
    ...sanitizedRequest,
    status: 'error',
    message,
    code: 401,
    webhook_auth: {
      authenticated: false
    }
  },
  pairedItem: {
    item: 0
  }
}];

const crypto = require('crypto');

// Validate input
const input = $input.first().json.body;
const normalizedText = String(input?.text || '').trim();

if (!input?.tenant_id || !input?.scope || !normalizedText) {
  return [{
    json: {
      error: 'Missing required fields: tenant_id, scope, text'
    }
  }];
}

// Secret patterns to reject
const secretPatterns = [
  /api[_-]?key/i,
  /bearer\s+[A-Za-z0-9-_.]+/i,
  /-----BEGIN(.*?)PRIVATE KEY-----/i
];

// Check for secrets in text
if (secretPatterns.some((p) => p.test(normalizedText))) {
  return [{
    json: {
      error: 'Rejected: potential secret detected in text'
    }
  }];
}

// Filter facts - only keep those with confidence >= 0.75 OR source == explicit
const filteredFacts = (input.facts || []).filter((f) => {
  // Check for secrets in fact fields
  const factText = `${f.subject || ''} ${f.predicate || ''} ${f.object || ''}`;
  if (secretPatterns.some((p) => p.test(factText))) {
    return false;
  }

  // Apply commit rules
  if (f.confidence >= 0.75 || input.source === 'explicit') {
    // Reject if subject/predicate/object empty
    if (!f.subject || !f.predicate || !f.object) {
      return false;
    }
    return true;
  }
  return false;
});

const requestId = input.request_id || `req-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
const source = String(input.source || 'unknown');
const tags = Array.isArray(input.tags) ? input.tags : [];
const metadata = (input.metadata && typeof input.metadata === 'object' && !Array.isArray(input.metadata))
  ? input.metadata
  : {};
const contentHash = crypto.createHash('sha256').update(normalizedText, 'utf8').digest('hex');

return [{
  json: {
    tenant_id: input.tenant_id,
    scope: input.scope,
    text: normalizedText,
    facts: filteredFacts,
    source,
    tags,
    metadata,
    request_id: requestId,
    content_hash: contentHash
  }
}];

const data = $input.first().json;

if (data.error) {
  return [{
    json: {
      status: 'error',
      message: data.error
    }
  }];
}

return [{
  json: data
}];

// Preserve the validated payload shape for cache lookup.
const data = $input.first().json;

return [{
  json: {
    ...data,
    content_hash: data.content_hash || null
  }
}];

// Check if we got a cache hit
const result = $input.first().json;
const hasCacheHit = result && result.length > 0 && result[0].id;

if (hasCacheHit) {
  // Return cache hit info
  const original = $('Compute Hash').first().json;
  return [{
    json: {
      ...original,
      cached: true,
      cached_id: result[0].id
    }
  }];
} else {
  // No cache - proceed with embedding generation
  const original = $('Compute Hash').first().json;
  return [{
    json: {
      ...original,
      cached: false
    }
  }];
}

